function DefaultCurrency591() {}
DefaultCurrency591.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency591.tabIndex = -1;
DefaultCurrency591.maxLength = 1;
DefaultCurrency591.isReadOnly = function(){return true;}
DefaultCurrency591.isTemporary = function(){return true;}
DefaultCurrency591.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency591.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
